// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007
long long calculateScore(long long num) {
    long long score = 0;
    long long temp = num;
    int digits[20];
    int count = 0;
    while (temp > 0) {
        digits[count++] = temp % 10;
        temp /= 10;
    }
    for (int i = 0; i < count; i++) {
        for (int j = i + 1; j < count; j++) {
            score = (score + abs(digits[i] - digits[j])) % MOD;
        }
    }
    return score;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long sum = 0;
        for (long long i = L; i <= R; i++) {
            sum = (sum + calculateScore(i)) % MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

